// Context
// ****************************************************************************************************************************************
type Context interface {
	Channel() string
	String() string
	Parse(interface{}) error
}

// messageContext *************************************************************************************************************************
type messageContext struct {
	m *redis_.Message
}

// Channel
// ****************************************************************************************************************************************
func (o *messageContext) Channel() string {
	return o.m.Channel
}

// String
// ****************************************************************************************************************************************
func (o *messageContext) String() string {
	return o.m.Payload
}

// Parse
// ****************************************************************************************************************************************
func (o *messageContext) Parse(dto interface{}) (err error) {
	return json.Unmarshal([]byte(o.m.Payload), dto)
}

